PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE d1_migrations(
		id         INTEGER PRIMARY KEY AUTOINCREMENT,
		name       TEXT UNIQUE,
		applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE TABLE `accessories` (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`uuid` text NOT NULL,
	`created_at` text DEFAULT 'CURRENT_TIMESTAMP',
	`updated_at` text DEFAULT 'CURRENT_TIMESTAMP'
);
CREATE TABLE `deadStocks` (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`shop_uuid` text NOT NULL,
	`name` text NOT NULL,
	`quantity` integer NOT NULL,
	`sold` integer NOT NULL,
	`mark` text,
	`lastSaleDate` text,
	`moveCount` integer,
	`moveToStore` text,
	`document_number` text NOT NULL,
	`document_date` text NOT NULL
);
CREATE TABLE `index_documents` (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`number` text NOT NULL,
	`shop_id` text NOT NULL,
	`close_date` text,
	`open_user_uuid` text,
	`type` text,
	`transactions` text
);
CREATE TABLE `openStors` (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`date` text NOT NULL,
	`userId` text NOT NULL,
	`cash` real,
	`sign` text,
	`ok` integer
);
CREATE TABLE `plan` (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`date` text NOT NULL,
	`shopUuid` text NOT NULL,
	`sum` real NOT NULL
);
CREATE TABLE `salary_bonus` (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`date` text DEFAULT 'CURRENT_TIMESTAMP',
	`salary` integer NOT NULL,
	`bonus` integer NOT NULL
);
CREATE TABLE `salaryData` (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`date` text NOT NULL,
	`shopUuid` text NOT NULL,
	`employeeUuid` text NOT NULL,
	`bonusAccessories` integer NOT NULL,
	`dataPlan` integer NOT NULL,
	`salesDataVape` integer NOT NULL,
	`bonusPlan` integer NOT NULL,
	`totalBonus` integer NOT NULL
);
CREATE TABLE `schedule` (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`shopUuid` text NOT NULL,
	`employeeUuid` text,
	`date` text NOT NULL,
	`shiftType` text
);
CREATE TABLE `shopProduct` (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`shopId` text NOT NULL,
	`uuid` text NOT NULL,
	`product_group` integer NOT NULL,
	`parentUuid` text,
	`name` text
);
CREATE TABLE products (
			    id INTEGER PRIMARY KEY AUTOINCREMENT,
                uuid TEXT,
                group_x BOOLEAN NOT NULL,
                parentUuid TEXT
            );
DELETE FROM sqlite_sequence;
CREATE INDEX `deadStocks_shop_uuid_idx` ON `deadStocks` (`shop_uuid`);
CREATE INDEX `deadStocks_document_number_idx` ON `deadStocks` (`document_number`);
CREATE INDEX `deadStocks_document_date_idx` ON `deadStocks` (`document_date`);
CREATE INDEX `idx_index_documents_shop_id` ON `index_documents` (`shop_id`);
CREATE INDEX `idx_index_documents_number` ON `index_documents` (`number`);
CREATE INDEX `idx_index_documents_type` ON `index_documents` (`type`);
CREATE UNIQUE INDEX `index_documents_number_shop_id_unique` ON `index_documents` (`number`,`shop_id`);
CREATE INDEX `openStors_userId_idx` ON `openStors` (`userId`);
CREATE INDEX `openStors_date_idx` ON `openStors` (`date`);
CREATE INDEX `idx_schedule_shopUuid` ON `schedule` (`shopUuid`);
CREATE INDEX `idx_schedule_date` ON `schedule` (`date`);
CREATE INDEX `idx_shopProduct_shopId` ON `shopProduct` (`shopId`);
CREATE INDEX `idx_shopProduct_uuid` ON `shopProduct` (`uuid`);
